CREATE DATABASE IF NOT EXISTS ledgerly; USE ledgerly;
CREATE TABLE items (id INT AUTO_INCREMENT PRIMARY KEY, name VARCHAR(150) NOT NULL, sku VARCHAR(60) UNIQUE, category VARCHAR(80), price DECIMAL(12,2) NOT NULL, stock INT DEFAULT 0, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE suppliers (id INT AUTO_INCREMENT PRIMARY KEY, name VARCHAR(150) NOT NULL, email VARCHAR(120), phone VARCHAR(50), address TEXT);
CREATE TABLE invoices (id INT AUTO_INCREMENT PRIMARY KEY, invoice_no VARCHAR(50) NOT NULL UNIQUE, customer_name VARCHAR(150) NOT NULL, supplier_name VARCHAR(150), supplier_address TEXT, supplier_phone VARCHAR(50), invoice_date DATE NOT NULL, gst_rate DECIMAL(5,2) DEFAULT 18.00, total DECIMAL(12,2) NOT NULL, status ENUM('Paid','Pending','Overdue') DEFAULT 'Pending', created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE invoice_items (id INT AUTO_INCREMENT PRIMARY KEY, invoice_id INT NOT NULL, item_id INT NOT NULL, quantity INT NOT NULL, unit_price DECIMAL(12,2) NOT NULL, FOREIGN KEY(invoice_id) REFERENCES invoices(id) ON DELETE CASCADE, FOREIGN KEY(item_id) REFERENCES items(id));
